        }

        if (!first) printf("\n");
        printf("commit %s\n", current);
        printf("Date: %s\n", timestamp);
        printf("Message: %s\n", message);
        first = 0;

        free(cdata);

        if (strcmp(parent, "NONE") == 0 || parent[0] == 0)
            break;
        strncpy(current, parent, sizeof(current) - 1);
        current[sizeof(current) - 1] = 0;
    }
    return 0;
}

